/* Test driver */
public class Main {
    public static void main(String[] args) {
        TrafficSignal s = new TrafficSignal("S1", "NS");
        if (s.getState() != SignalState.RED) { System.out.println("FAIL: initial"); System.exit(1); }
        s.advance();
        if (s.getState() != SignalState.GREEN) { System.out.println("FAIL: green"); System.exit(1); }
        s.advance();
        if (s.getState() != SignalState.YELLOW) { System.out.println("FAIL: yellow"); System.exit(1); }
        s.advance();
        if (s.getState() != SignalState.RED) { System.out.println("FAIL: red"); System.exit(1); }
        System.out.println("OK_CYCLE");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Intersection it = new Intersection("X", 2, 1);
        it.addSignal("NS"); it.addSignal("EW");
        it.initialize(new String[]{"NS","EW"});
        if (it.getSignal("NS").getState() != SignalState.GREEN) { System.out.println("FAIL: init"); System.exit(1); }
        it.tick(); it.tick(); it.tick();
        if (it.getSignal("EW").getState() != SignalState.GREEN) { System.out.println("FAIL: switch"); System.exit(1); }
        System.out.println("OK_SWITCH");
    }
}

/* Test driver */
public class Main {
    public static void main(String[] args) {
        Intersection it = new Intersection("X", 5, 2);
        it.addSignal("NS"); it.addSignal("EW");
        it.initialize(new String[]{"NS","EW"});
        it.emergencyOverride("EW");
        if (it.getSignal("EW").getState() != SignalState.GREEN) { System.out.println("FAIL: ew"); System.exit(1); }
        if (it.getSignal("NS").getState() != SignalState.RED) { System.out.println("FAIL: ns"); System.exit(1); }
        for (int i = 0; i < 20; i++) it.tick();
        if (it.getSignal("EW").getState() != SignalState.GREEN) { System.out.println("FAIL: frozen"); System.exit(1); }
        System.out.println("OK_EMERGENCY");
    }
}
